import { scope } from "arktype";

// Define the schema using scope and export
const types = scope({
  Node: {
    id: "number % 1 >= 0",
    label: "1 <= string <= 40",
    edges: "Node[]"
  },
  Graph: {
    rootId: "number % 1 >= 0",
    nodes: "1 <= Node[] <= 1000"
  }
}).export();

// Extract TypeScript types from the exported scope if needed
export type Node = typeof types.Node.infer;
export type Graph = typeof types.Graph.infer;

// Attach the narrow predicate to the Graph type
export const GraphSchema = types.Graph.narrow((g, ctx) => {
  const ids = new Set<number>();
  for (const node of g.nodes) {
    if (ids.has(node.id)) {
      ctx.error({ code: "predicate", problem: `duplicate node id: ${node.id}` });
      return false;
    }
    ids.add(node.id);
  }

  for (const node of g.nodes) {
    for (const edge of node.edges) {
      if (!ids.has(edge.id)) {
        ctx.error({ code: "predicate", problem: `edge target id ${edge.id} does not exist in nodes` });
        return false;
      }
    }
  }

  if (!ids.has(g.rootId)) {
    ctx.error({ code: "predicate", problem: `rootId ${g.rootId} does not exist in nodes` });
    return false;
  }

  return true;
});

/**
 * Validates a directed graph.
 * Returns the validated Graph or throws on invalid input.
 */
export function validateGraph(input: unknown): Graph {
  return GraphSchema.assert(input);
}

import * as fs from "node:fs";
import { validateGraph } from "./src/validator.js";

function main() {
  try {
    const inputStr = fs.readFileSync(0, "utf-8").trim();
    if (!inputStr) {
      console.log("INVALID: empty input");
      return;
    }

    let payload: unknown;
    try {
      payload = JSON.parse(inputStr);
    } catch (e: any) {
      console.log(`INVALID: invalid JSON: ${e.message}`);
      return;
    }

    if (typeof payload !== "object" || payload === null) {
      console.log("INVALID: input must be a JSON object");
      return;
    }

    if (!("graph" in payload)) {
      console.log("INVALID: missing 'graph' key in input");
      return;
    }

    try {
      const validated = validateGraph((payload as any).graph);
      console.log("VALID");
      console.log(JSON.stringify(validated));
    } catch (e: any) {
      console.log(`INVALID: ${e.message}`);
    }
  } catch (e: any) {
    console.log(`INVALID: unexpected error: ${e.message}`);
  }
}

main();

import { spawnSync } from "node:child_process";

const testCases = [
  {
    name: "Case 1: Valid 3-node graph with cycle A -> B -> C -> A",
    input: {
      graph: {
        rootId: 1,
        nodes: [
          {
            id: 1,
            label: "A",
            edges: [
              {
                id: 2,
                label: "B",
                edges: [
                  {
                    id: 3,
                    label: "C",
                    edges: [
                      {
                        id: 1,
                        label: "A",
                        edges: []
                      }
                    ]
                  }
                ]
              }
            ]
          },
          {
            id: 2,
            label: "B",
            edges: [
              {
                id: 3,
                label: "C",
                edges: [
                  {
                    id: 1,
                    label: "A",
                    edges: []
                  }
                ]
              }
            ]
          },
          {
            id: 3,
            label: "C",
            edges: [
              {
                id: 1,
                label: "A",
                edges: []
              }
            ]
          }
        ]
      }
    },
    expectedValid: true
  },
  {
    name: "Case 2: Graph with duplicate node IDs",
    input: {
      graph: {
        rootId: 1,
        nodes: [
          { "id": 1, "label": "A", "edges": [] },
          { "id": 1, "label": "B", "edges": [] }
        ]
      }
    },
    expectedValid: false,
    expectedErrorSubstring: "duplicate node id"
  },
  {
    name: "Case 3: Graph where some edge points to an ID that does not appear in nodes",
    input: {
      graph: {
        rootId: 1,
        nodes: [
          {
            id: 1,
            label: "A",
            edges: [
              { "id": 99, "label": "Missing", "edges": [] }
            ]
          }
        ]
      }
    },
    expectedValid: false,
    expectedErrorSubstring: "edge target id 99 does not exist in nodes"
  },
  {
    name: "Case 4: Graph that contains a node with a negative ID",
    input: {
      graph: {
        rootId: 1,
        nodes: [
          { "id": -1, "label": "A", "edges": [] }
        ]
      }
    },
    expectedValid: false,
    expectedErrorSubstring: "must be non-negative"
  },
  {
    name: "Case 5: Graph with a node whose label has length 41",
    input: {
      graph: {
        rootId: 1,
        nodes: [
          { "id": 1, "label": "12345678901234567890123456789012345678901", "edges": [] }
        ]
      }
    },
    expectedValid: false,
    expectedErrorSubstring: "must be at most length 40"
  },
  {
    name: "Case 6: Graph whose rootId is not present in nodes",
    input: {
      graph: {
        rootId: 4,
        nodes: [
          { "id": 1, "label": "A", "edges": [] }
        ]
      }
    },
    expectedValid: false,
    expectedErrorSubstring: "rootId 4 does not exist in nodes"
  }
];

let failed = false;

for (const tc of testCases) {
  console.log(`Running ${tc.name}...`);
  const child = spawnSync("npx", ["tsx", "cli.ts"], {
    input: JSON.stringify(tc.input),
    encoding: "utf-8"
  });

  if (child.status !== 0) {
    console.error(`  FAIL: Exit code was ${child.status}, expected 0`);
    failed = true;
    continue;
  }

  const lines = child.stdout.trim().split("\n");
  const firstLine = lines[0];

  if (tc.expectedValid) {
    if (firstLine !== "VALID") {
      console.error(`  FAIL: Expected VALID but got: ${firstLine}`);
      console.error(`  Stderr: ${child.stderr}`);
      console.error(`  Stdout: ${child.stdout}`);
      failed = true;
    } else {
      console.log(`  PASS: Validated successfully`);
      try {
        const parsed = JSON.parse(lines[1]);
        if (parsed.rootId !== tc.input.graph.rootId) {
          console.error(`  FAIL: Parsed rootId does not match`);
          failed = true;
        }
      } catch (e: any) {
        console.error(`  FAIL: Could not parse second line as JSON: ${e.message}`);
        failed = true;
      }
    }
  } else {
    if (!firstLine.startsWith("INVALID:")) {
      console.error(`  FAIL: Expected INVALID: ... but got: ${firstLine}`);
      console.error(`  Stderr: ${child.stderr}`);
      console.error(`  Stdout: ${child.stdout}`);
      failed = true;
    } else {
      const errorMsg = firstLine.substring("INVALID:".length).trim();
      const sub = tc.expectedErrorSubstring || "";
      if (!errorMsg.toLowerCase().includes(sub.toLowerCase())) {
        console.error(`  FAIL: Expected error message to contain "${sub}", but got "${errorMsg}"`);
        failed = true;
      } else {
        console.log(`  PASS: Rejected correctly with message: "${errorMsg}"`);
      }
    }
  }
}

if (failed) {
  console.log("\nSome tests FAILED.");
  process.exit(1);
} else {
  console.log("\nAll tests PASSED successfully!");
}
